class RideTrackingScreen extends ConsumerStatefulWidget {\n  final String rideId;\n  \n  const RideTrackingScreen({\n    super.key,\n    required this.rideId,\n  });\n  \n  @override\n  ConsumerState<RideTrackingScreen> createState() => _RideTrackingScreenState();\n}\n\nclass _RideTrackingScreenState extends ConsumerState<RideTrackingScreen> {\n  GoogleMapController? _mapController;\n  final Set<Marker> _markers = {};\n  final Set<Polyline> _polylines = {};\n  StreamSubscription<Position>? _positionStream;\n  \n  bool _isMapLoaded = false;\n  bool _isFollowingDriver = true;\n  bool _showDriverInfo = false;\n  LatLng? _currentUserLocation;\n  \n  final double _defaultZoom = 16.0;\n  \n  @override\n  void initState() {\n    super.initState();\n    _initializeTracking();\n    _startLocationTracking();\n  }\n  \n  @override\n  void dispose() {\n    _positionStream?.cancel();\n    _mapController?.dispose();\n    super.dispose();\n  }\n  \n  void _initializeTracking() {\n    WidgetsBinding.instance.addPostFrameCallback((_) {\n      ref.read(rideTrackingProvider(widget.rideId).notifier)\n        .startTracking();\n    });\n  }\n  \n  void _startLocationTracking() async {\n    try {\n      final permission = await Geolocator.checkPermission();\n      if (permission == LocationPermission.denied) {\n        final requestedPermission = await Geolocator.requestPermission();\n        if (requestedPermission == LocationPermission.denied) {\n          return;\n        }\n      }\n      \n      _positionStream = Geolocator.getPositionStream(\n        locationSettings: const LocationSettings(\n          accuracy: LocationAccuracy.high,\n          distanceFilter: 5,\n        ),\n      ).listen((position) {\n        setState(() {\n          _currentUserLocation = LatLng(position.latitude, position.longitude);\n        });\n        \n        // Actualizar ubicación del pasajero\n        ref.read(rideTrackingProvider(widget.rideId).notifier)\n          .updatePassengerLocation(\n            position.latitude,\n            position.longitude,\n          );\n      });\n    } catch (e) {\n      if (kDebugMode) {
        Logger().error('Error starting location tracking', error: e);
      }\n    }\n  }\n  \n  void _onMapCreated(GoogleMapController controller) {\n    _mapController = controller;\n    \n    // Aplicar estilo de mapa personalizado\n    MapUtils.setMapStyle(_mapController!);\n    \n    setState(() {\n      _isMapLoaded = true;\n    });\n  }\n  \n  void _updateMapMarkers(RideTrackingState tracking) {\n    _markers.clear();\n    \n    // Marcador del conductor\n    if (tracking.driverLocation != null) {\n      _markers.add(\n        Marker(\n          markerId: const MarkerId('driver'),\n          position: LatLng(\n            tracking.driverLocation!.lat,\n            tracking.driverLocation!.lng,\n          ),\n          icon: BitmapDescriptor.defaultMarkerWithHue(BitmapDescriptor.hueOrange),\n          infoWindow: InfoWindow(\n            title: tracking.driverInfo?.name ?? 'Conductor',\n            snippet: 'Llegada estimada: ${tracking.estimatedArrival} min',\n          ),\n          rotation: tracking.driverLocation!.bearing ?? 0.0,\n        ),\n      );\n    }\n    \n    // Marcador del pasajero (ubicación actual)\n    if (_currentUserLocation != null) {\n      _markers.add(\n        Marker(\n          markerId: const MarkerId('passenger'),\n          position: _currentUserLocation!,\n          icon: BitmapDescriptor.defaultMarkerWithHue(BitmapDescriptor.hueBlue),\n          infoWindow: const InfoWindow(\n            title: 'Tu ubicación',\n          ),\n        ),\n      );\n    }\n    \n    // Marcadores de pickup y destino\n    if (tracking.pickupLocation != null) {\n      _markers.add(\n        Marker(\n          markerId: const MarkerId('pickup'),\n          position: LatLng(\n            tracking.pickupLocation!.lat,\n            tracking.pickupLocation!.lng,\n          ),\n          icon: BitmapDescriptor.defaultMarkerWithHue(BitmapDescriptor.hueGreen),\n          infoWindow: InfoWindow(\n            title: 'Punto de recogida',\n            snippet: tracking.pickupAddress,\n          ),\n        ),\n      );\n    }\n    \n    if (tracking.destinationLocation != null) {\n      _markers.add(\n        Marker(\n          markerId: const MarkerId('destination'),\n          position: LatLng(\n            tracking.destinationLocation!.lat,\n            tracking.destinationLocation!.lng,\n          ),\n          icon: BitmapDescriptor.defaultMarkerWithHue(BitmapDescriptor.hueRed),\n          infoWindow: InfoWindow(\n            title: 'Destino',\n            snippet: tracking.destinationAddress,\n          ),\n        ),\n      );\n    }\n  }\n  \n  void _updateMapRoute(RideTrackingState tracking) {\n    _polylines.clear();\n    \n    if (tracking.route != null && tracking.route!.isNotEmpty) {\n      _polylines.add(\n        Polyline(\n          polylineId: const PolylineId('route'),\n          points: tracking.route!.map(\n            (point) => LatLng(point.lat, point.lng),\n          ).toList(),\n          color: AppColors.primary,\n          width: 4,\n          patterns: tracking.status == RideStatus.completed \n            ? [PatternItem.dash(10), PatternItem.gap(5)]\n            : [],\n        ),\n      );\n    }\n  }\n  \n  void _centerMapOnDriver(RideTrackingState tracking) {\n    if (_mapController == null || tracking.driverLocation == null) return;\n    \n    _mapController!.animateCamera(\n      CameraUpdate.newCameraPosition(\n        CameraPosition(\n          target: LatLng(\n            tracking.driverLocation!.lat,\n            tracking.driverLocation!.lng,\n          ),\n          zoom: _defaultZoom,\n        ),\n      ),\n    );\n  }\n  \n  void _fitMarkersInView() {\n    if (_mapController == null || _markers.isEmpty) return;\n    \n    final bounds = MapUtils.calculateBounds(_markers.map((m) => m.position).toList());\n    \n    _mapController!.animateCamera(\n      CameraUpdate.newLatLngBounds(bounds, 100.0),\n    );\n  }\n  \n  @override\n  Widget build(BuildContext context) {\n    final trackingState = ref.watch(rideTrackingProvider(widget.rideId));\n    \n    return Scaffold(\n      body: trackingState.when(\n        data: (tracking) => _buildTrackingView(tracking),\n        loading: () => const Center(\n          child: CircularProgressIndicator(),\n        ),\n        error: (error, stack) => _buildErrorView(error),\n      ),\n    );\n  }\n  \n  Widget _buildTrackingView(RideTrackingState tracking) {\n    // Actualizar marcadores y rutas\n    _updateMapMarkers(tracking);\n    _updateMapRoute(tracking);\n    \n    return Stack(\n      children: [\n        // Mapa principal\n        GoogleMap(\n          onMapCreated: _onMapCreated,\n          initialCameraPosition: CameraPosition(\n            target: tracking.driverLocation != null\n              ? LatLng(tracking.driverLocation!.lat, tracking.driverLocation!.lng)\n              : const LatLng(-12.046374, -77.042793), // Lima por defecto\n            zoom: _defaultZoom,\n          ),\n          markers: _markers,\n          polylines: _polylines,\n          myLocationEnabled: true,\n          myLocationButtonEnabled: false,\n          mapToolbarEnabled: false,\n          zoomControlsEnabled: false,\n          compassEnabled: false,\n          onTap: (_) {\n            // Ocultar panel de información si está visible\n            if (_showDriverInfo) {\n              setState(() {\n                _showDriverInfo = false;\n              });\n            }\n          },\n        ),\n        \n        // Header con información del viaje\n        Positioned(\n          top: 0,\n          left: 0,\n          right: 0,\n          child: _buildHeader(tracking),\n        ),\n        \n        // Controles del mapa\n        Positioned(\n          right: 16,\n          top: 120,\n          child: _buildMapControls(tracking),\n        ),\n        \n        // Panel principal con información del conductor\n        Positioned(\n          bottom: 0,\n          left: 0,\n          right: 0,\n          child: _buildBottomPanel(tracking),\n        ),\n        \n        // Panel de información extendido del conductor\n        if (_showDriverInfo)\n          Positioned(\n            bottom: 0,\n            left: 0,\n            right: 0,\n            child: _buildDriverInfoPanel(tracking),\n          ),\n        \n        // Botón de emergencia\n        Positioned(\n          top: MediaQuery.of(context).padding.top + 60,\n          left: 16,\n          child: EmergencyButton(\n            onPressed: () => _handleEmergency(tracking),\n          ),\n        ),\n      ],\n    );\n  }\n  \n  Widget _buildHeader(RideTrackingState tracking) {\n    return Container(\n      padding: EdgeInsets.only(\n        top: MediaQuery.of(context).padding.top,\n        left: 16,\n        right: 16,\n        bottom: 16,\n      ),\n      decoration: BoxDecoration(\n        color: Colors.white,\n        boxShadow: [\n          BoxShadow(\n            color: Colors.black.withOpacity(0.1),\n            blurRadius: 10,\n            offset: const Offset(0, 2),\n          ),\n        ],\n      ),\n      child: SafeArea(\n        bottom: false,\n        child: Column(\n          children: [\n            Row(\n              children: [\n                IconButton(\n                  onPressed: () => Navigator.pop(context),\n                  icon: const Icon(Icons.arrow_back),\n                ),\n                Expanded(\n                  child: RideStatusCard(\n                    status: tracking.status,\n                    estimatedArrival: tracking.estimatedArrival,\n                  ),\n                ),\n              ],\n            ),\n            \n            // Timer de llegada (solo si no ha llegado el conductor)\n            if (tracking.status == RideStatus.accepted ||\n                tracking.status == RideStatus.driverAssigned)\n              Container(\n                margin: const EdgeInsets.only(top: 8),\n                child: ArrivalTimer(\n                  estimatedArrival: tracking.estimatedArrival ?? 0,\n                  onUpdate: (remaining) {\n                    // Actualizar timer\n                  },\n                ),\n              ),\n          ],\n        ),\n      ),\n    );\n  }\n  \n  Widget _buildMapControls(RideTrackingState tracking) {\n    return Column(\n      children: [\n        // Botón para seguir al conductor\n        Container(\n          decoration: BoxDecoration(\n            color: Colors.white,\n            borderRadius: BorderRadius.circular(8),\n            boxShadow: [\n              BoxShadow(\n                color: Colors.black.withOpacity(0.1),\n                blurRadius: 5,\n                offset: const Offset(0, 2),\n              ),\n            ],\n          ),\n          child: IconButton(\n            onPressed: () {\n              setState(() {\n                _isFollowingDriver = !_isFollowingDriver;\n              });\n              if (_isFollowingDriver) {\n                _centerMapOnDriver(tracking);\n              }\n            },\n            icon: Icon(\n              _isFollowingDriver\n                ? Icons.my_location\n                : Icons.location_searching,\n              color: _isFollowingDriver\n                ? AppColors.primary\n                : Colors.grey[600],\n            ),\n          ),\n        ),\n        \n        const SizedBox(height: 8),\n        \n        // Botón para ver todos los marcadores\n        Container(\n          decoration: BoxDecoration(\n            color: Colors.white,\n            borderRadius: BorderRadius.circular(8),\n            boxShadow: [\n              BoxShadow(\n                color: Colors.black.withOpacity(0.1),\n                blurRadius: 5,\n                offset: const Offset(0, 2),\n              ),\n            ],\n          ),\n          child: IconButton(\n            onPressed: _fitMarkersInView,\n            icon: const Icon(Icons.zoom_out_map),\n          ),\n        ),\n        \n        const SizedBox(height: 8),\n        \n        // Botón para llamar al conductor\n        if (tracking.driverInfo?.phone != null)\n          Container(\n            decoration: BoxDecoration(\n              color: Colors.green,\n              borderRadius: BorderRadius.circular(8),\n              boxShadow: [\n                BoxShadow(\n                  color: Colors.black.withOpacity(0.1),\n                  blurRadius: 5,\n                  offset: const Offset(0, 2),\n                ),\n              ],\n            ),\n            child: IconButton(\n              onPressed: () => _callDriver(tracking.driverInfo!.phone!),\n              icon: const Icon(Icons.phone, color: Colors.white),\n            ),\n          ),\n      ],\n    );\n  }\n  \n  Widget _buildBottomPanel(RideTrackingState tracking) {\n    return Container(\n      decoration: BoxDecoration(\n        color: Colors.white,\n        borderRadius: const BorderRadius.only(\n          topLeft: Radius.circular(24),\n          topRight: Radius.circular(24),\n        ),\n        boxShadow: [\n          BoxShadow(\n            color: Colors.black.withOpacity(0.1),\n            blurRadius: 10,\n            offset: const Offset(0, -5),\n          ),\n        ],\n      ),\n      child: Column(\n        mainAxisSize: MainAxisSize.min,\n        children: [\n          // Handle para arrastrar\n          Container(\n            margin: const EdgeInsets.only(top: 8),\n            width: 40,\n            height: 4,\n            decoration: BoxDecoration(\n              color: Colors.grey[300],\n              borderRadius: BorderRadius.circular(2),\n            ),\n          ),\n          \n          // Información del conductor\n          if (tracking.driverInfo != null)\n            GestureDetector(\n              onTap: () {\n                setState(() {\n                  _showDriverInfo = !_showDriverInfo;\n                });\n              },\n              child: Container(\n                padding: const EdgeInsets.all(16),\n                child: DriverInfoCard(\n                  driver: tracking.driverInfo!,\n                  vehicleInfo: tracking.vehicleInfo,\n                  showExpanded: false,\n                ),\n              ),\n            ),\n          \n          // Panel de acciones\n          TripActionsPanel(\n            status: tracking.status,\n            onCancel: () => _cancelRide(tracking),\n            onShare: () => _shareTrip(tracking),\n            onChat: () => _openChat(tracking),\n            onRateDriver: tracking.status == RideStatus.completed\n              ? () => _rateDriver(tracking)\n              : null,\n          ),\n          \n          // Padding inferior para safe area\n          SizedBox(height: MediaQuery.of(context).padding.bottom),\n        ],\n      ),\n    ).animate().slideY(\n      begin: 1,\n      duration: const Duration(milliseconds: 300),\n      curve: Curves.easeOutQuart,\n    );\n  }\n  \n  Widget _buildDriverInfoPanel(RideTrackingState tracking) {\n    if (tracking.driverInfo == null) return const SizedBox.shrink();\n    \n    return Container(\n      height: MediaQuery.of(context).size.height * 0.6,\n      decoration: BoxDecoration(\n        color: Colors.white,\n        borderRadius: const BorderRadius.only(\n          topLeft: Radius.circular(24),\n          topRight: Radius.circular(24),\n        ),\n        boxShadow: [\n          BoxShadow(\n            color: Colors.black.withOpacity(0.2),\n            blurRadius: 20,\n            offset: const Offset(0, -10),\n          ),\n        ],\n      ),\n      child: Column(\n        children: [\n          // Header del panel\n          Container(\n            padding: const EdgeInsets.all(16),\n            decoration: BoxDecoration(\n              color: AppColors.primary,\n              borderRadius: const BorderRadius.only(\n                topLeft: Radius.circular(24),\n                topRight: Radius.circular(24),\n              ),\n            ),\n            child: Row(\n              children: [\n                CircleAvatar(\n                  radius: 30,\n                  backgroundImage: tracking.driverInfo!.photo != null\n                    ? CachedNetworkImageProvider(tracking.driverInfo!.photo!)\n                    : null,\n                  child: tracking.driverInfo!.photo == null\n                    ? const Icon(Icons.person, size: 30, color: Colors.white)\n                    : null,\n                ),\n                const SizedBox(width: 16),\n                Expanded(\n                  child: Column(\n                    crossAxisAlignment: CrossAxisAlignment.start,\n                    children: [\n                      Text(\n                        tracking.driverInfo!.name,\n                        style: const TextStyle(\n                          color: Colors.white,\n                          fontSize: 20,\n                          fontWeight: FontWeight.bold,\n                        ),\n                      ),\n                      const SizedBox(height: 4),\n                      Row(\n                        children: [\n                          const Icon(Icons.star, size: 16, color: Colors.amber),\n                          const SizedBox(width: 4),\n                          Text(\n                            tracking.driverInfo!.rating.toStringAsFixed(1),\n                            style: const TextStyle(\n                              color: Colors.white,\n                              fontWeight: FontWeight.bold,\n                            ),\n                          ),\n                          const SizedBox(width: 8),\n                          Text(\n                            '(${tracking.driverInfo!.totalTrips} viajes)',\n                            style: const TextStyle(\n                              color: Colors.white70,\n                              fontSize: 12,\n                            ),\n                          ),\n                        ],\n                      ),\n                    ],\n                  ),\n                ),\n                IconButton(\n                  onPressed: () {\n                    setState(() {\n                      _showDriverInfo = false;\n                    });\n                  },\n                  icon: const Icon(Icons.close, color: Colors.white),\n                ),\n              ],\n            ),\n          ),\n          \n          // Contenido del panel\n          Expanded(\n            child: SingleChildScrollView(\n              padding: const EdgeInsets.all(20),\n              child: Column(\n                crossAxisAlignment: CrossAxisAlignment.start,\n                children: [\n                  // Información del vehículo\n                  if (tracking.vehicleInfo != null) ..[\n                    _buildInfoSection(\n                      title: 'Vehículo',\n                      icon: Icons.directions_car,\n                      children: [\n                        _buildInfoRow(\n                          label: 'Modelo',\n                          value: '${tracking.vehicleInfo!.make} ${tracking.vehicleInfo!.model}',\n                        ),\n                        _buildInfoRow(\n                          label: 'Color',\n                          value: tracking.vehicleInfo!.color,\n                        ),\n                        _buildInfoRow(\n                          label: 'Placa',\n                          value: tracking.vehicleInfo!.licensePlate,\n                        ),\n                      ],\n                    ),\n                    const SizedBox(height: 20),\n                  ],\n                  \n                  // Estadísticas del conductor\n                  _buildInfoSection(\n                    title: 'Estadísticas',\n                    icon: Icons.analytics,\n                    children: [\n                      _buildInfoRow(\n                        label: 'Viajes completados',\n                        value: tracking.driverInfo!.totalTrips.toString(),\n                      ),\n                      _buildInfoRow(\n                        label: 'Años conduciendo',\n                        value: tracking.driverInfo!.yearsExperience?.toString() ?? 'N/A',\n                      ),\n                      _buildInfoRow(\n                        label: 'Tasa de aceptación',\n                        value: '${(tracking.driverInfo!.acceptanceRate * 100).toStringAsFixed(0)}%',\n                      ),\n                    ],\n                  ),\n                  \n                  const SizedBox(height: 20),\n                  \n                  // Comentarios recientes\n                  if (tracking.driverInfo!.recentComments != null &&\n                      tracking.driverInfo!.recentComments!.isNotEmpty) ..[\n                    _buildInfoSection(\n                      title: 'Comentarios recientes',\n                      icon: Icons.comment,\n                      children: tracking.driverInfo!.recentComments!.map(\n                        (comment) => Container(\n                          padding: const EdgeInsets.all(12),\n                          margin: const EdgeInsets.only(bottom: 8),\n                          decoration: BoxDecoration(\n                            color: Colors.grey[50],\n                            borderRadius: BorderRadius.circular(8),\n                          ),\n                          child: Text(\n                            comment,\n                            style: const TextStyle(fontSize: 14),\n                          ),\n                        ),\n                      ).toList(),\n                    ),\n                    const SizedBox(height: 20),\n                  ],\n                  \n                  // Botones de acción\n                  Row(\n                    children: [\n                      if (tracking.driverInfo!.phone != null)\n                        Expanded(\n                          child: CustomButton(\n                            text: 'Llamar',\n                            onPressed: () => _callDriver(tracking.driverInfo!.phone!),\n                            icon: Icons.phone,\n                            backgroundColor: Colors.green,\n                          ),\n                        ),\n                      if (tracking.driverInfo!.phone != null)\n                        const SizedBox(width: 12),\n                      Expanded(\n                        child: CustomButton(\n                          text: 'Mensajes',\n                          onPressed: () => _openChat(tracking),\n                          icon: Icons.chat,\n                          backgroundColor: AppColors.primary,\n                        ),\n                      ),\n                    ],\n                  ),\n                ],\n              ),\n            ),\n          ),\n        ],\n      ),\n    ).animate().slideY(\n      begin: 1,\n      duration: const Duration(milliseconds: 400),\n      curve: Curves.easeOutQuart,\n    );\n  }\n  \n  Widget _buildInfoSection({\n    required String title,\n    required IconData icon,\n    required List<Widget> children,\n  }) {\n    return Column(\n      crossAxisAlignment: CrossAxisAlignment.start,\n      children: [\n        Row(\n          children: [\n            Icon(icon, size: 20, color: AppColors.primary),\n            const SizedBox(width: 8),\n            Text(\n              title,\n              style: const TextStyle(\n                fontSize: 16,\n                fontWeight: FontWeight.bold,\n              ),\n            ),\n          ],\n        ),\n        const SizedBox(height: 12),\n        ...children,\n      ],\n    );\n  }\n  \n  Widget _buildInfoRow({\n    required String label,\n    required String value,\n  }) {\n    return Padding(\n      padding: const EdgeInsets.only(bottom: 8),\n      child: Row(\n        mainAxisAlignment: MainAxisAlignment.spaceBetween,\n        children: [\n          Text(\n            label,\n            style: const TextStyle(\n              color: Colors.grey,\n              fontSize: 14,\n            ),\n          ),\n          Text(\n            value,\n            style: const TextStyle(\n              fontWeight: FontWeight.w500,\n              fontSize: 14,\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n  \n  Widget _buildErrorView(Object error) {\n    return Center(\n      child: Padding(\n        padding: const EdgeInsets.all(32),\n        child: Column(\n          mainAxisAlignment: MainAxisAlignment.center,\n          children: [\n            const Icon(\n              Icons.error_outline,\n              size: 80,\n              color: Colors.red,\n            ),\n            const SizedBox(height: 20),\n            const Text(\n              'Error al cargar el seguimiento',\n              style: TextStyle(\n                fontSize: 20,\n                fontWeight: FontWeight.bold,\n              ),\n            ),\n            const SizedBox(height: 12),\n            Text(\n              error.toString(),\n              textAlign: TextAlign.center,\n              style: const TextStyle(\n                color: Colors.grey,\n              ),\n            ),\n            const SizedBox(height: 32),\n            CustomButton(\n              text: 'Reintentar',\n              onPressed: _initializeTracking,\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n  \n  void _callDriver(String phoneNumber) async {\n    final uri = Uri.parse('tel:$phoneNumber');\n    if (await canLaunchUrl(uri)) {\n      await launchUrl(uri);\n    } else {\n      if (mounted) {\n        ScaffoldMessenger.of(context).showSnackBar(\n          const SnackBar(\n            content: Text('No se puede realizar la llamada'),\n            backgroundColor: Colors.red,\n          ),\n        );\n      }\n    }\n  }\n  \n  void _cancelRide(RideTrackingState tracking) async {\n    final confirmed = await showDialog<bool>(\n      context: context,\n      builder: (context) => AlertDialog(\n        title: const Text('¿Cancelar viaje?'),\n        content: const Text(\n          '¿Estás seguro de que deseas cancelar este viaje?',\n        ),\n        actions: [\n          TextButton(\n            onPressed: () => Navigator.pop(context, false),\n            child: const Text('No'),\n          ),\n          ElevatedButton(\n            onPressed: () => Navigator.pop(context, true),\n            style: ElevatedButton.styleFrom(\n              backgroundColor: Colors.red,\n            ),\n            child: const Text('Sí, cancelar'),\n          ),\n        ],\n      ),\n    );\n    \n    if (confirmed == true && mounted) {\n      LoadingOverlay.show(context);\n      try {\n        await ref.read(rideTrackingProvider(widget.rideId).notifier)\n          .cancelRide('Cancelado por el pasajero');\n        \n        if (mounted) {\n          LoadingOverlay.hide(context);\n          Navigator.pop(context);\n        }\n      } catch (e) {\n        if (mounted) {\n          LoadingOverlay.hide(context);\n          ScaffoldMessenger.of(context).showSnackBar(\n            SnackBar(\n              content: Text('Error al cancelar: $e'),\n              backgroundColor: Colors.red,\n            ),\n          );\n        }\n      }\n    }\n  }\n  \n  void _shareTrip(RideTrackingState tracking) {\n    // Implementar compartir viaje\n    // Esto podría generar un link compartible con la ubicación en tiempo real\n  }\n  \n  void _openChat(RideTrackingState tracking) {\n    // Navegar al chat con el conductor\n    Navigator.pushNamed(\n      context,\n      '/chat',\n      arguments: {\n        'chatId': '${widget.rideId}_${tracking.driverInfo?.id}',\n        'recipientName': tracking.driverInfo?.name ?? 'Conductor',\n        'recipientPhoto': tracking.driverInfo?.photo,\n      },\n    );\n  }\n  \n  void _rateDriver(RideTrackingState tracking) {\n    // Navegar a la pantalla de calificación\n    Navigator.pushNamed(\n      context,\n      '/rate-driver',\n      arguments: {\n        'rideId': widget.rideId,\n        'driverInfo': tracking.driverInfo,\n      },\n    );\n  }\n  \n  void _handleEmergency(RideTrackingState tracking) async {\n    LoadingOverlay.show(context);\n    try {\n      await ref.read(rideTrackingProvider(widget.rideId).notifier)\n        .triggerEmergency({\n          'location': _currentUserLocation != null\n            ? {\n                'lat': _currentUserLocation!.latitude,\n                'lng': _currentUserLocation!.longitude,\n              }\n            : null,\n          'driverId': tracking.driverInfo?.id,\n          'rideId': widget.rideId,\n        });\n      \n      if (mounted) {\n        LoadingOverlay.hide(context);\n        ScaffoldMessenger.of(context).showSnackBar(\n          const SnackBar(\n            content: Text('Alerta de emergencia enviada'),\n            backgroundColor: Colors.orange,\n          ),\n        );\n      }\n    } catch (e) {\n      if (mounted) {\n        LoadingOverlay.hide(context);\n        ScaffoldMessenger.of(context).showSnackBar(\n          SnackBar(\n            content: Text('Error al enviar alerta: $e'),\n            backgroundColor: Colors.red,\n          ),\n        );\n      }\n    }\n  }\n}